import { getArgsFromUrl, getArgsFromUrlHash } from '@badam/common-utils'

export type Product = 'ksa' | 'ludo' | 'jawwy'

export const JAWWY_APP_STORE_URL =
  'https://apps.apple.com/gb/app/%D8%B3%D9%88%D8%A7-%D8%AC%D9%88-%D9%8A-%D8%AA%D9%88%D8%A7%D8%B5%D9%84-%D8%A7%D8%AC%D8%AA%D9%85%D8%A7%D8%B9%D9%8A/id6755757268'

export const LUDO_APP_STORE_URL =
  'https://apps.apple.com/pk/app/sawa-ludo-%D9%84%D9%88%D8%AF%D9%88-%D8%AF%D9%88%D9%85%D9%8A%D9%86%D9%88/id6443823893'

export function getProduct(): Product {
  const app = getArgsFromUrlHash('a') || getArgsFromUrl('a') || '0'

  if (app === '1') {
    return 'ludo'
  }

  if (app === '2') {
    return 'jawwy'
  }

  return 'ksa'
}
